import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getSaleById, updateSale } from "../../api/saleApi";
import { getAuth } from "../../utils/auth";

export default function EditSale() {
  const { id } = useParams();
  const navigate = useNavigate();

  const { role } = getAuth();
  const canManage = role === "admin" || role === "manager";

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");

  const [sale, setSale] = useState(null);

  const [form, setForm] = useState({
    price: "",
    payment_status: "pending",
  });

  useEffect(() => {
    if (!canManage) {
      alert("Access denied");
      navigate("/vehicles");
      return;
    }

    const load = async () => {
      setError("");
      setLoading(true);
      try {
        const res = await getSaleById(id);
        const s = res.data;
        setSale(s);

        setForm({
          price: s.price ?? "",
          payment_status: s.payment_status || "pending",
        });
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load sale");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [id, canManage, navigate]);

  const onChange = (e) => {
    const { name, value } = e.target;
    setForm((p) => ({ ...p, [name]: value }));
  };

  const submit = async (e) => {
    e.preventDefault();
    setError("");

    if (form.price === "" || Number(form.price) < 0) return setError("Price must be 0 or more");

    setSaving(true);
    try {
      await updateSale(id, {
        price: Number(form.price),
        payment_status: form.payment_status,
      });

      alert("Updated!");
      navigate("/sales");
    } catch (err) {
      setError(err.response?.data?.message || "Update failed");
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <p style={{ padding: 20 }}>Loading...</p>;

  if (error && !sale) {
    return (
      <div className="page">
        <div className="card cardPad" style={{ maxWidth: 720, margin: "32px auto" }}>
          <div style={{ padding: 12, borderRadius: "var(--radius)", border: "1px solid var(--danger)", backgroundColor: "rgba(244, 67, 54, 0.1)", color: "var(--danger)" }}>
            <b>Error:</b> {error}
          </div>
          <button onClick={() => navigate("/sales")} className="btn" style={{ marginTop: 12 }}>
            Back
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit Sale</div>
          <div className="pageSub">Update sale details and payment status</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 720, margin: "32px auto" }}>
        {/* Sale summary */}
        <div style={{ marginBottom: 16, padding: 12, border: "1px solid var(--border)", borderRadius: "var(--radius)" }}>
          <div style={{ fontSize: 14 }}>
            <b>Vehicle:</b>{" "}
            {sale?.vehicle?.brand
              ? `${sale.vehicle.brand} ${sale.vehicle.model || sale.vehicle.type || ""}`
              : "-"}
          </div>
          <div style={{ fontSize: 14, marginTop: 6 }}>
            <b>Customer:</b> {sale?.customer?.name || "-"}
          </div>
          <div style={{ fontSize: 12, opacity: 0.75, marginTop: 6 }}>
            Created: {sale?.createdAt ? new Date(sale.createdAt).toLocaleString() : "-"}
          </div>
        </div>

        {error && (
          <div style={{ marginBottom: 16, padding: 12, borderRadius: "var(--radius)", border: "1px solid var(--danger)", backgroundColor: "rgba(244, 67, 54, 0.1)", color: "var(--danger)" }}>
            <b>Error:</b> {error}
          </div>
        )}

        <form onSubmit={submit}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
            <div>
              <label className="label">Price (Rs.)</label>
              <input
                className="input"
                name="price"
                type="number"
                min="0"
                value={form.price}
                onChange={onChange}
                required
              />
            </div>

            <div>
              <label className="label">Payment Status</label>
              <select
                className="select"
                name="payment_status"
                value={form.payment_status}
                onChange={onChange}
              >
                <option value="pending">Pending</option>
                <option value="partial">Partial</option>
                <option value="completed">Completed</option>
              </select>

              <div style={{ marginTop: 6, fontSize: 12, opacity: 0.75 }}>
                If you set <b>completed</b>, backend will mark vehicle as <b>sold</b>.
              </div>
            </div>
          </div>

          <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
            <button type="submit" className="btn btnPrimary" disabled={saving}>
              {saving ? "Saving..." : "Save Changes"}
            </button>
            <button type="button" className="btn" onClick={() => navigate("/sales")} disabled={saving}>
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
